public int guessNumber(int n) {
    int left = 1, right = n;
    while (left <= right) {
        int mid = left + (right - left) / 2;
        int result = guess(mid);
        if (result == 0) return mid;
        if (result == 1) left = mid + 1;
        else right = mid - 1;
    }
    return -1;
}
```

